-namespace
-{
-
-  static const TypeFunc *gtest_void_void_type()
-  {
-    return OptoRuntime::void_void_Type();
-  }
-
-  static void gtest_noop_stub(JavaThread *thread)
-  {
-    (void)thread;
-  }
-
-  class ScopedCompilerThreadForGraph : public StackObj
-  {
-    Thread *_saved_thread;
-    CompileQueue *_queue;
-    CompilerThread *_compiler_thread;
-
-  public:
-    ScopedCompilerThreadForGraph()
-        : _saved_thread(Thread::current()),
-          _queue(new CompileQueue("gtest-opto-queue")),
-          _compiler_thread(new CompilerThread(_queue, new CompilerCounters()))
-    {
-      _compiler_thread->set_compiler(CompileBroker::compiler(CompLevel_full_optimization));
-      _compiler_thread->record_stack_base_and_size();
-
-      Thread::clear_thread_current();
-      _compiler_thread->initialize_thread_current();
-    }
-
-    ~ScopedCompilerThreadForGraph()
-    {
-      Thread::clear_thread_current();
-      _saved_thread->initialize_thread_current();
-      // Deleting a synthetic CompilerThread created this way can block during
-      // JavaThread teardown in gtest; keep it alive for process lifetime.
-    }
-  };
-
-}
-
-TEST_VM(opto, phi_node_ideal_graph)
-{
-  ::setenv("MY_DBG", "1", 1);
-  if (CompileBroker::compiler(CompLevel_full_optimization) == nullptr)
-  {
-    GTEST_SKIP() << "C2 compiler is not available";
-  }
-
-  ScopedCompilerThreadForGraph compiler_thread_scope;
-
-  Arena ci_arena(mtCompiler, Arena::Tag::tag_cienv);
-  alignas(ciEnv) char env_storage[sizeof(ciEnv)];
-  ciEnv *env = ::new (env_storage) ciEnv(&ci_arena);
-
-  DirectiveSet *directive = DirectivesStack::getDefaultDirective(CompileBroker::compiler(CompLevel_full_optimization));
-  Compile compile(env,
-                  gtest_void_void_type,
-                  CAST_FROM_FN_PTR(address, gtest_noop_stub),
-                  "gtest_phi_node_ideal_graph",
-                  100001,
-                  0,
-                  false,
-                  false,
-                  directive);
-  DirectivesStack::release(directive);
-
-  ASSERT_FALSE(compile.failing());
-
-  env->set_compiler_data(&compile);
-
-  PhaseGVN gvn;
-
-  Node *ctrl = compile.start()->proj_out(TypeFunc::Control);
-  ASSERT_NE(ctrl, nullptr);
-
-  RegionNode *region = new RegionNode(3);
-  region->init_req(1, ctrl);
-  region->init_req(2, compile.top());
-
-  gvn.set_type(ctrl, Type::CONTROL);
-  gvn.set_type(compile.top(), Type::TOP);
-  (void)gvn.transform(region);
-
-  PhiNode *phi = new PhiNode(region, TypeInt::INT);
-  phi->init_req(1, gvn.intcon(11));
-  phi->init_req(2, gvn.intcon(42));
-
-  Node *transformed = gvn.transform(phi);
-  env->set_compiler_data(nullptr);
-  CompilerThread::current()->set_env(nullptr);
-
-  ASSERT_TRUE(transformed->is_ConI());
-  ASSERT_EQ(transformed->as_ConI()->get_int(), 11);
-}
-
-TEST_VM(opto, phi_node_ideal_memory_chain_dead_phi_repro)
-{
-  ::setenv("MY_DBG", "1", 1);
-  if (CompileBroker::compiler(CompLevel_full_optimization) == nullptr)
-  {
-    GTEST_SKIP() << "C2 compiler is not available";
-  }
-
-  ScopedCompilerThreadForGraph compiler_thread_scope;
-
-  Arena ci_arena(mtCompiler, Arena::Tag::tag_cienv);
-  alignas(ciEnv) char env_storage[sizeof(ciEnv)];
-  ciEnv *env = ::new (env_storage) ciEnv(&ci_arena);
-
-  DirectiveSet *directive = DirectivesStack::getDefaultDirective(CompileBroker::compiler(CompLevel_full_optimization));
-  Compile compile(env,
-                  gtest_void_void_type,
-                  CAST_FROM_FN_PTR(address, gtest_noop_stub),
-                  "gtest_phi_node_ideal_memory_chain_dead_phi_repro",
-                  100002,
-                  0,
-                  false,
-                  false,
-                  directive);
-  DirectivesStack::release(directive);
-
-  ASSERT_FALSE(compile.failing());
-  env->set_compiler_data(&compile);
-
-  compile.node_hash()->clear();
-  compile.igvn_worklist()->clear();
-
-  PhaseGVN bootstrap_gvn;
-  PhaseIterGVN igvn(&bootstrap_gvn);
-
-  Node *ctrl = compile.start()->proj_out(TypeFunc::Control);
-  Node *start_mem = compile.start()->proj_out(TypeFunc::Memory);
-  ASSERT_NE(ctrl, nullptr);
-  ASSERT_NE(start_mem, nullptr);
-
-  RegionNode *region = new RegionNode(3);
-  region->init_req(1, ctrl);
-  region->init_req(2, ctrl);
-
-  igvn.set_type(ctrl, Type::CONTROL);
-  igvn.set_type(start_mem, Type::MEMORY);
-  igvn.set_type(compile.top(), Type::TOP);
-  (void)igvn.transform(region);
-
-  const TypeOopPtr *known_inst_field = TypeInstPtr::NOTNULL->cast_to_instance_id(1)->add_offset(BytesPerInt)->is_oopptr();
-  int alias_idx = compile.get_alias_index(known_inst_field);
-
-  PhiNode *mem_phi = new PhiNode(region,
-                                 Type::MEMORY,
-                                 known_inst_field,
-                                 -1,
-                                 known_inst_field->instance_id(),
-                                 alias_idx,
-                                 known_inst_field->offset());
-
-  MergeMemNode *mmem = MergeMemNode::make(compile.top());
-  mmem->set_memory_at(Compile::AliasIdxRaw, mem_phi);
-
-  mem_phi->init_req(1, mmem);
-  mem_phi->init_req(2, start_mem);
-  ASSERT_EQ(mem_phi->outcnt(), 1U);
-
-  // Reproducer shape:
-  //   mem_phi(in1=mmem, in2=start_mem), and mmem.slice(alias)=mem_phi.
-  // During PhiNode::Ideal, optimize_memory_chain() transforms mmem and can
-  // remove it, making mem_phi dead while mem_phi is still in transform_old().
-  Node *transformed = igvn.transform(mem_phi);
-
-  ASSERT_EQ(mmem->outcnt(), 0U);
-  ASSERT_TRUE(mem_phi->outcnt() == 0 || mem_phi->in(0) == nullptr);
-
-  env->set_compiler_data(nullptr);
-  CompilerThread::current()->set_env(nullptr);
-
-  ASSERT_NE(transformed, nullptr);
-}
